const SCROLL_BASELINE_CHIPS: { label: string; minutes: number }[] = [
  { label: "~15m", minutes: 15 },
  { label: "~30m", minutes: 30 },
  { label: "~1h", minutes: 60 },
  { label: "~2h", minutes: 120 },
  { label: "3h+", minutes: 180 },
];

function snapToNearestChip(minutes: number): number {
  let best = SCROLL_BASELINE_CHIPS[0].minutes;
  let bestDist = Math.abs(minutes - best);
  for (const chip of SCROLL_BASELINE_CHIPS) {
    const dist = Math.abs(minutes - chip.minutes);
    if (dist < bestDist) {
      best = chip.minutes;
      bestDist = dist;
    }
  }
  return best;
}

