// Onboarding flow shown to first-time users. Order = on-screen order.
//   0 → Hero (Turn Scrolling Into Energy)
//   1 → Persona Selection (What Goal Brought You Here?)
//   2 → Name + Goal + Scroll Estimate
//   3 → Difficulty (Chill / Balanced / Beast)
//   4 → Lock the Vault (app picker + iOS Screen Time / Android Usage Access)
//   5 → Trust Bridge (Volt Respects Your Hustle) → auth / sign-up
const onboardingScreens: ScreenKey[] = [
  "onboarding1",
  "onboarding2",
  "onboarding4",
  "onboarding5",
  "onboarding3",
  "onboarding6",
];

const SKIN_COLORS: Record<string, { body: string; blush: string; bolt: string }> = {
  skin_default: { body: C.mint, blush: "rgba(255,45,120,0.2)", bolt: C.electricYellow },
  skin_flame:   { body: "#FF6B35", blush: "rgba(255,200,50,0.3)", bolt: "#FFD700" },
  skin_ice:     { body: "#88E0EF", blush: "rgba(150,200,255,0.3)", bolt: "#FFFFFF" },
  skin_shadow:  { body: "#2D2D2D", blush: "rgba(100,100,100,0.3)", bolt: "#9B59B6" },
  skin_gold:    { body: "#FFD700", blush: "rgba(255,215,0,0.3)", bolt: "#FFA500" },
  skin_rainbow: { body: "#FF69B4", blush: "rgba(255,105,180,0.2)", bolt: "#00FF00" },
};

function VoltMascot({
  size = 80,
  variant = "normal",
  skin,
}: {
  readonly size?: number;
  readonly variant?: "normal" | "waving" | "celebrating";
  readonly skin?: string;
}) {
  const h = size * 1.25;
  const sc = SKIN_COLORS[skin ?? "skin_default"] ?? SKIN_COLORS.skin_default;
  return (
    <Svg width={size} height={h} viewBox="0 0 80 100">
      <Rect x={26} y={2} width={28} height={12} rx={5} fill={sc.body} stroke={C.black} strokeWidth={2.5} />
      <Rect x={8} y={14} width={64} height={78} rx={14} fill={sc.body} stroke={C.black} strokeWidth={2.5} />
      <Circle cx={30} cy={40} r={6} fill={C.black} />
      <Circle cx={32} cy={37} r={2.5} fill={C.white} />
      <Circle cx={50} cy={40} r={6} fill={C.black} />
      <Circle cx={52} cy={37} r={2.5} fill={C.white} />
      <Circle cx={19} cy={48} r={5} fill={sc.blush} />
      <Circle cx={61} cy={48} r={5} fill={sc.blush} />
      <Path d="M30 54 Q40 64 50 54" stroke={C.black} strokeWidth={2.5} fill="none" strokeLinecap="round" />
      <Path d="M42 68 L38 78 H46 L42 88" stroke={sc.bolt} strokeWidth={3} fill="none" strokeLinecap="round" strokeLinejoin="round" />
      {variant === "waving" ? (
        <>
          <Path d="M8 42 Q0 34 6 24" stroke={C.black} strokeWidth={2.5} fill="none" strokeLinecap="round" />
          <Circle cx={6} cy={23} r={3} fill={C.black} />
          <Path d="M72 42 Q80 50 76 58" stroke={C.black} strokeWidth={2.5} fill="none" strokeLinecap="round" />
        </>
      ) : variant === "celebrating" ? (
        <>
          <Path d="M8 38 Q-2 28 6 18" stroke={C.black} strokeWidth={2.5} fill="none" strokeLinecap="round" />
          <Circle cx={6} cy={17} r={3} fill={C.black} />
          <Path d="M72 38 Q82 28 74 18" stroke={C.black} strokeWidth={2.5} fill="none" strokeLinecap="round" />
          <Circle cx={74} cy={17} r={3} fill={C.black} />
        </>
      ) : (
        <>
          <Path d="M8 48 Q2 54 4 62" stroke={C.black} strokeWidth={2.5} fill="none" strokeLinecap="round" />
          <Path d="M72 48 Q78 54 76 62" stroke={C.black} strokeWidth={2.5} fill="none" strokeLinecap="round" />
        </>
      )}
    </Svg>
  );
}

