  const dailyShuffledByCategory = useMemo(() => {
    const daySeed = CURRENT_UTC_DAY_INDEX;
    function seededShuffle<T>(arr: T[], seed: number): T[] {
      const copy = [...arr];
      let s = seed;
      for (let i = copy.length - 1; i > 0; i--) {
        s = ((s * 1103515245 + 12345) & 0x7fffffff);
        const j = s % (i + 1);
        [copy[i], copy[j]] = [copy[j], copy[i]];
      }
      return copy;
    }
    const cats: ActivityCategory[] = ["physical", "mindful", "micro", "anti-scroll"];
    const result: Record<ActivityCategory, typeof ACTIVITIES> = {} as any;
    for (const cat of cats) {
      const catActivities = ACTIVITIES.filter((a) => a.category === cat);
      result[cat] = seededShuffle(catActivities, daySeed + cat.codePointAt(0)!);
    }
    return result;
  }, []);

